  selectTab(tab: TabItem): void {
    if (tab.disabled) return;

    this.activeId.set(tab.id);
    this.tabChange.emit(tab);
  }

  isActive(tab: TabItem): boolean {
    return this.activeId()
      ? this.activeId() === tab.id
      : this.tabs()[0]?.id === tab.id;
  }
}

