type AlertColor = 'success' | 'warning' | 'danger' | 'info';

@Component({
  selector: 'ui-alert',
  standalone: true,
  imports: [NgClass, NgIf],
  templateUrl: './ui-alert.component.html',
  styleUrl: './ui-alert.component.scss',
})
export class UiAlertComponent {
  @Input() message = 'Mensagem do alerta';
  @Input() color: AlertColor = 'info';
  @Input() icon?: string;
  @Input() closable = true;
  @Input() fixed = true;
  @Input() visible = true;

  @Output() closed = new EventEmitter<void>();

  close(): void {
    this.visible = false;
    this.closed.emit();
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
} from '@angular/core';
import {
  UiColor,
  UiHorizontalPosition,
  UiSize,
} from '@design-system/types/ui.types';

@Component({
  selector: 'ui-button',
  standalone: true,
  templateUrl: './ui-button.component.html',
  styleUrl: './ui-button.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class UiButtonComponent {
  label = input('Button');
  color = input<UiColor>('primary');
  size = input<UiSize>('md');
  position = input<UiHorizontalPosition>('center');
  disabled = input(false);
  fullWidth = input(false);
  rounded = input(false);
  outline = input(false);
  icon = input<string | null>(null);
  iconPosition = input<'left' | 'right'>('left');
  customClass = input('');
  type = input<'button' | 'submit' | 'reset'>('button');

  buttonClick = output<void>();

  buttonClasses = computed(() =>
    [
      'ui-button',
      `ui-button--${this.color()}`,
      `ui-button--${this.size()}`,
      this.outline() ? 'ui-button--outline' : '',
      this.fullWidth() ? 'ui-button--full' : '',
      this.rounded() ? 'ui-button--rounded' : '',
      this.disabled() ? 'ui-button--disabled' : '',
      this.customClass(),
    ]
      .filter(Boolean)
      .join(' '),
  );

  wrapperClasses = computed(
    () => `ui-button-wrapper ui-button-wrapper--${this.position()}`,
  );

  onClick(): void {
    if (!this.disabled()) {
      this.buttonClick.emit();
    }
  }
}

