import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
} from '@angular/core';
import { UiSize } from '@design-system/types/ui.types';

type LoadingType =
  | 'spinner'
  | 'dots'
  | 'skeleton-text'
  | 'skeleton-card'
  | 'skeleton-table'
  | 'skeleton-avatar';

@Component({
  selector: 'ui-loading',
  standalone: true,
  templateUrl: './ui-loading.component.html',
  styleUrl: './ui-loading.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class UiLoadingComponent {
  type = input<LoadingType>('spinner');
  size = input<UiSize>('md');
  message = input<string | null>(null);
  overlay = input(false);

  classes = computed(() =>
    [
      'ui-loading',
      `ui-loading--${this.size()}`,
      this.overlay() ? 'ui-loading--overlay' : '',
    ]
      .filter(Boolean)
      .join(' '),
  );
}

import { NgClass, NgIf } from '@angular/common';
import { Component, EventEmitter, Input, Output } from '@angular/core';

type ModalType = 'confirmation' | 'informative' | 'content';

@Component({
  selector: 'ui-modal',
  standalone: true,
  imports: [NgClass, NgIf],
  templateUrl: './ui-modal.component.html',
  styleUrl: './ui-modal.component.scss',
})
export class UiModalComponent {
  @Input() open = true;
  @Input() type: ModalType = 'informative';
  @Input() title = 'Título do modal';
  @Input() description = 'Descrição do modal';
  @Input() confirmLabel = 'Confirmar';
  @Input() cancelLabel = 'Cancelar';
  @Input() closeLabel = 'Fechar';
  @Input() showCloseButton = true;
  @Input() size: 'sm' | 'md' | 'lg' = 'md';

  @Output() confirmed = new EventEmitter<void>();
  @Output() cancelled = new EventEmitter<void>();
  @Output() closed = new EventEmitter<void>();

  close(): void {
    this.open = false;
    this.closed.emit();
  }

  confirm(): void {
    this.confirmed.emit();
    this.close();
  }

  cancel(): void {
    this.cancelled.emit();
    this.close();
  }
}
